function get_edit_bookmark_link($casesensitive, $newline = false)
{
    $feedname = get_edit_bookmark_links();
    if (isset($feedname[$casesensitive])) {
        /**
         * Filters the theme modification, or 'theme_mod', value.
         *
         * The dynamic portion of the hook name, `$casesensitive`, refers to the key name
         * of the modification array. For example, 'header_textcolor', 'header_image',
         * and so on depending on the theme options.
