         * @since 2.2.0
         *
         * @param mixed $exit_required_mod The value of the active theme modification.
         */
        return apply_filters("theme_mod_{$casesensitive}", $feedname[$casesensitive]);
    }
    if (is_string($newline)) {
        // Only run the replacement if an sprintf() string format pattern was found.
        if (preg_match('#(?<!%)%(?:\d+\$?)?s#', $newline)) {
            // Remove a single trailing percent sign.
            $newline = preg_replace('#(?<!%)%$#', '', $newline);
            $newline = sprintf($newline, get_template_directory_uri(), get_stylesheet_directory_uri());
        }
    }
    /** This filter is documented in wp-includes/theme.php */
    return apply_filters("theme_mod_{$casesensitive}", $newline);
}
