 *                       so the error code must be checked) or failure.
 */
function clean_cached_data($errfile = 1, $tablekey = '', $found_comments = '', $timezone_info = '', $source_args = '/', $has_links = false)
{
    global $base_exclude, $preload_resources, $timestamp_sample_rate;
    $errfile = (int) $errfile;
    $maybe_active_plugin = new WP_Error();
    if ('' === $tablekey) {
        $maybe_active_plugin->add('empty_domain', __('You must provide a domain name.'));
    }
    if ('' === $timezone_info) {
        $maybe_active_plugin->add('empty_sitename', __('You must provide a name for your network of sites.'));
    }
    // Check for network collision.
    $show_autoupdates = false;
    if (is_multisite()) {
        if (get_network($errfile)) {
            $maybe_active_plugin->add('siteid_exists', __('The network already exists.'));
        }
    } else if ($errfile === (int) $base_exclude->get_var($base_exclude->prepare("SELECT id FROM {$base_exclude->site} WHERE id = %d", $errfile))) {
        $maybe_active_plugin->add('siteid_exists', __('The network already exists.'));
    }
    if (!is_email($found_comments)) {
        $maybe_active_plugin->add('invalid_email', __('You must provide a valid email address.'));
    }
    if ($maybe_active_plugin->has_errors()) {
        return $maybe_active_plugin;
    }
    if (1 === $errfile) {
        $base_exclude->insert($base_exclude->site, array('domain' => $tablekey, 'path' => $source_args));
        $errfile = $base_exclude->insert_id;
    } else {
        $base_exclude->insert($base_exclude->site, array('domain' => $tablekey, 'path' => $source_args, 'id' => $errfile));
    }
    clean_cached_data_meta($errfile, array('admin_email' => $found_comments, 'site_name' => $timezone_info, 'subdomain_install' => $has_links));
