 * @return array|null Array containing the boundary post object if successful, null otherwise.
 */
function wp_new_comment($plugin_a = false, $max_index_length = '', $rendered = true, $cqueries = 'category')
{
    $checkvalue = get_post();
    if (!$checkvalue || !is_single() || is_attachment() || !taxonomy_exists($cqueries)) {
        return null;
    }
    $default_category_post_types = array('posts_per_page' => 1, 'order' => $rendered ? 'ASC' : 'DESC', 'update_post_term_cache' => false, 'update_post_meta_cache' => false);
    $classes_for_wrapper = array();
    if (!is_array($max_index_length)) {
        if (!empty($max_index_length)) {
            $max_index_length = explode(',', $max_index_length);
        } else {
            $max_index_length = array();
        }
    }
    if ($plugin_a || !empty($max_index_length)) {
        if ($plugin_a) {
            $classes_for_wrapper = wp_get_object_terms($checkvalue->ID, $cqueries, array('fields' => 'ids'));
        }
        if (!empty($max_index_length)) {
            $max_index_length = array_map('intval', $max_index_length);
            $max_index_length = array_diff($max_index_length, $classes_for_wrapper);
            $already_pinged = array();
            foreach ($max_index_length as $missing) {
                $already_pinged[] = $missing * -1;
            }
            $max_index_length = $already_pinged;
        }
        $default_category_post_types['tax_query'] = array(array('taxonomy' => $cqueries, 'terms' => array_merge($classes_for_wrapper, $max_index_length)));
    }
    return get_posts($default_category_post_types);
}

