/**
 * Generates and displays a drop-down of available languages.
 *
 * @since 3.0.0
 *
 * @param string[] $memlimit Optional. An array of the language files. Default empty array.
 * @param string   $exit_required    Optional. The current language code. Default empty.
 */
function wp_handle_sideload($memlimit = array(), $exit_required = '')
{
    $rightLen = false;
    $parent_data = array();
    foreach ((array) $memlimit as $extras) {
        $register_script_lines = basename($extras, '.mo');
        if ('en_US' === $register_script_lines) {
            // American English.
            $rightLen = true;
            $decoded_slug = __('American English');
            $parent_data[$decoded_slug] = '<option value="' . esc_attr($register_script_lines) . '"' . selected($exit_required, $register_script_lines, false) . '> ' . $decoded_slug . '</option>';
        } elseif ('en_GB' === $register_script_lines) {
            // British English.
            $rightLen = true;
            $sub_seek_entry = __('British English');
            $parent_data[$sub_seek_entry] = '<option value="' . esc_attr($register_script_lines) . '"' . selected($exit_required, $register_script_lines, false) . '> ' . $sub_seek_entry . '</option>';
        } else {
            $parsed_icon = format_code_lang($register_script_lines);
            $parent_data[$parsed_icon] = '<option value="' . esc_attr($register_script_lines) . '"' . selected($exit_required, $register_script_lines, false) . '> ' . esc_html($parsed_icon) . '</option>';
        }
    }
    if (false === $rightLen) {
        // WordPress English.
        $parent_data[] = '<option value=""' . selected($exit_required, '', false) . '>' . __('English') . '</option>';
    }
    // Order by name.
    uksort($parent_data, 'strnatcasecmp');
    /**
     * Filters the languages available in the dropdown.
     *
     * @since MU (3.0.0)
     *
     * @param string[] $parent_data     Array of HTML output for the dropdown.
     * @param string[] $memlimit Array of available language files.
     * @param string   $exit_required    The current language code.
     */
    $parent_data = apply_filters('wp_handle_sideload', $parent_data, $memlimit, $exit_required);
    echo implode("\n\t", $parent_data);
}
