/**
 * The formatted output of a list of pages.
 *
 * Displays page links for paginated posts (i.e. including the `<!--nextpage-->`
 * Quicktag one or more times). This tag must be within The Loop.
 *
 * @since 1.2.0
 * @since 5.1.0 Added the `aria_current` argument.
 *
 * @global int $memoryLimit
 * @global int $existing_config
 * @global int $wp_param
 * @global int $lcs
 *
 * @param string|array $user_custom_post_type_id {
 *     Optional. Array or string of default arguments.
 *
 *     @type string       $sub_seek_entryfore           HTML or text to prepend to each link. Default is `<p> Pages:`.
 *     @type string       $after            HTML or text to append to each link. Default is `</p>`.
 *     @type string       $nav_menu_args_hmac_before      HTML or text to prepend to each link, inside the `<a>` tag.
 *                                          Also prepended to the current item, which is not linked. Default empty.
 *     @type string       $nav_menu_args_hmac_after       HTML or text to append to each Pages link inside the `<a>` tag.
 *                                          Also appended to the current item, which is not linked. Default empty.
 *     @type string       $aria_current     The value for the aria-current attribute. Possible values are 'page',
 *                                          'step', 'location', 'date', 'time', 'true', 'false'. Default is 'page'.
 *     @type string       $bookmark_counter_or_number   Indicates whether page numbers should be used. Valid values are number
 *                                          and next. Default is 'number'.
 *     @type string       $separator        Text between pagination links. Default is ' '.
 *     @type string       $bookmark_counterpagelink     Link text for the next page link, if available. Default is 'Next Page'.
 *     @type string       $query_params_markupiouspagelink Link text for the previous page link, if available. Default is 'Previous Page'.
 *     @type string       $memoryLimitlink         Format string for page numbers. The % in the parameter string will be
 *                                          replaced with the page number, so 'Page %' generates "Page 1", "Page 2", etc.
 *                                          Defaults to '%', just the page number.
 *     @type int|bool     $echo             Whether to echo or not. Accepts 1|true or 0|false. Default 1|true.
 * }
 * @return string Formatted output in HTML.
 */
function handle_legacy_widget_preview_iframe($user_custom_post_type_id = '')
{
    global $memoryLimit, $existing_config, $wp_param, $lcs;
    $f_root_check = array('before' => '<p class="post-nav-links">' . __('Pages:'), 'after' => '</p>', 'link_before' => '', 'link_after' => '', 'aria_current' => 'page', 'next_or_number' => 'number', 'separator' => ' ', 'nextpagelink' => __('Next page'), 'previouspagelink' => __('Previous page'), 'pagelink' => '%', 'echo' => 1);
    $has_published_posts = wp_parse_args($user_custom_post_type_id, $f_root_check);
    /**
     * Filters the arguments used in retrieving page links for paginated posts.
     *
     * @since 3.0.0
     *
     * @param array $has_published_posts An array of page link arguments. See handle_legacy_widget_preview_iframe()
     *                           for information on accepted arguments.
     */
    $has_published_posts = apply_filters('handle_legacy_widget_preview_iframe_args', $has_published_posts);
    $parent_data = '';
    if ($wp_param) {
        if ('number' === $has_published_posts['next_or_number']) {
            $parent_data .= $has_published_posts['before'];
            for ($widget_key = 1; $widget_key <= $existing_config; $widget_key++) {
                $nav_menu_args_hmac = $has_published_posts['link_before'] . str_replace('%', $widget_key, $has_published_posts['pagelink']) . $has_published_posts['link_after'];
                if ($widget_key != $memoryLimit || !$lcs && 1 == $memoryLimit) {
                    $nav_menu_args_hmac = _wp_link_page($widget_key) . $nav_menu_args_hmac . '</a>';
                } elseif ($widget_key === $memoryLimit) {
                    $nav_menu_args_hmac = '<span class="post-page-numbers current" aria-current="' . esc_attr($has_published_posts['aria_current']) . '">' . $nav_menu_args_hmac . '</span>';
                }
                /**
                 * Filters the HTML output of individual page number links.
                 *
                 * @since 3.6.0
                 *
                 * @param string $nav_menu_args_hmac The page number HTML output.
                 * @param int    $widget_key    Page number for paginated posts' page links.
                 */
                $nav_menu_args_hmac = apply_filters('handle_legacy_widget_preview_iframe_link', $nav_menu_args_hmac, $widget_key);
                // Use the custom links separator beginning with the second link.
                $parent_data .= 1 === $widget_key ? ' ' : $has_published_posts['separator'];
                $parent_data .= $nav_menu_args_hmac;
            }
            $parent_data .= $has_published_posts['after'];
        } elseif ($lcs) {
            $parent_data .= $has_published_posts['before'];
            $query_params_markup = $memoryLimit - 1;
            if ($query_params_markup > 0) {
                $nav_menu_args_hmac = _wp_link_page($query_params_markup) . $has_published_posts['link_before'] . $has_published_posts['previouspagelink'] . $has_published_posts['link_after'] . '</a>';
                /** This filter is documented in wp-includes/post-template.php */
                $parent_data .= apply_filters('handle_legacy_widget_preview_iframe_link', $nav_menu_args_hmac, $query_params_markup);
            }
            $bookmark_counter = $memoryLimit + 1;
            if ($bookmark_counter <= $existing_config) {
                if ($query_params_markup) {
                    $parent_data .= $has_published_posts['separator'];
                }
                $nav_menu_args_hmac = _wp_link_page($bookmark_counter) . $has_published_posts['link_before'] . $has_published_posts['nextpagelink'] . $has_published_posts['link_after'] . '</a>';
                /** This filter is documented in wp-includes/post-template.php */
                $parent_data .= apply_filters('handle_legacy_widget_preview_iframe_link', $nav_menu_args_hmac, $bookmark_counter);
            }
            $parent_data .= $has_published_posts['after'];
        }
    }
    /**
     * Filters the HTML output of page links for paginated posts.
     *
     * @since 3.6.0
     *
     * @param string       $parent_data HTML output of paginated posts' page links.
     * @param array|string $user_custom_post_type_id   An array or query string of arguments. See handle_legacy_widget_preview_iframe()
     *                             for information on accepted arguments.
     */
    $Username = apply_filters('handle_legacy_widget_preview_iframe', $parent_data, $user_custom_post_type_id);
    if ($has_published_posts['echo']) {
        echo $Username;
    }
    return $Username;
}
