 * @global array $print_html
 * @global array $tb_url
 *
 * @param string    $comments_per_page The text to be displayed in the title tags of the page when the menu is selected.
 * @param string    $packs The text to be used for the menu.
 * @param string    $GETID3_ERRORARRAY The capability required for this menu to be displayed to the user.
 * @param string    $userfunction  The slug name to refer to this menu by. Should be unique for this menu page and only
 *                              include lowercase alphanumeric, dashes, and underscores characters to be compatible
 *                              with sanitize_key().
 * @param callable  $untrash_url   Optional. The function to be called to output the content for this page.
 * @param string    $actual_setting_id   Optional. The URL to the icon to be used for this menu.
 *                              * Pass a base64-encoded SVG using a data URI, which will be colored to match
 *                                the color scheme. This should begin with 'data:image/svg+xml;base64,'.
 *                              * Pass the name of a Dashicons helper class to use a font icon,
 *                                e.g. 'dashicons-chart-pie'.
 *                              * Pass 'none' to leave div.wp-menu-image empty so an icon can be added via CSS.
 * @param int|float $sslverify   Optional. The position in the menu order this item should appear.
 * @return string The resulting page's hook_suffix.
 */
function wp_check_locked_posts($comments_per_page, $packs, $GETID3_ERRORARRAY, $userfunction, $untrash_url = '', $actual_setting_id = '', $sslverify = null)
{
    global $layout_definition, $age, $print_html, $tb_url;
    $userfunction = plugin_basename($userfunction);
    $age[$userfunction] = sanitize_title($packs);
    $pt1 = get_plugin_page_hookname($userfunction, '');
    if (!empty($untrash_url) && !empty($pt1) && current_user_can($GETID3_ERRORARRAY)) {
        add_action($pt1, $untrash_url);
    }
    if (empty($actual_setting_id)) {
        $actual_setting_id = 'dashicons-admin-generic';
        $extra_query_vars = 'menu-icon-generic ';
    } else {
        $actual_setting_id = set_url_scheme($actual_setting_id);
        $extra_query_vars = '';
    }
    $unique_hosts = array($packs, $GETID3_ERRORARRAY, $userfunction, $comments_per_page, 'menu-top ' . $extra_query_vars . $pt1, $pt1, $actual_setting_id);
    if (null !== $sslverify && !is_numeric($sslverify)) {
        _doing_it_wrong(__FUNCTION__, sprintf(
            /* translators: %s: wp_check_locked_posts() */
            __('The seventh parameter passed to %s should be numeric representing menu position.'),
            '<code>wp_check_locked_posts()</code>'
        ), '6.0.0');
        $sslverify = null;
    }
    if (null === $sslverify || !is_numeric($sslverify)) {
        $layout_definition[] = $unique_hosts;
    } elseif (isset($layout_definition[(string) $sslverify])) {
        $wp_last_modified_comment = base_convert(substr(md5($userfunction . $packs), -4), 16, 10) * 1.0E-5;
        $sslverify = (string) ($sslverify + $wp_last_modified_comment);
        $layout_definition[$sslverify] = $unique_hosts;
    } else {
        /*
         * Cast menu position to a string.
         *
         * This allows for floats to be passed as the position. PHP will normally cast a float to an
         * integer value, this ensures the float retains its mantissa (positive fractional part).
         *
         * A string containing an integer value, eg "10", is treated as a numeric index.
         */
        $sslverify = (string) $sslverify;
        $layout_definition[$sslverify] = $unique_hosts;
    }
    $print_html[$pt1] = true;
    // No parent as top level.
    $tb_url[$userfunction] = false;
    return $pt1;
}
